import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { CORE_MODULES, OPTIONAL_MODULES } from '@/constants'

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const availableModules = ref([])

  // 将布局对象转换为数组
  const convertLayoutToArray = (layoutObj) => {
    return Object.entries(layoutObj)
      .filter(([_, config]) => config.visible)
      .map(([type, config]) => ({
        type,
        order: config.order || 0,
        visible: config.visible
      }))
      .sort((a, b) => a.order - b.order)
  }

  // 计算属性：核心模块
  const coreModules = computed(() => {
    return activeModules.value.filter(module => 
      CORE_MODULES.includes(module.type)
    ).sort((a, b) => a.order - b.order)
  })

  // 计算属性：可选模块
  const optionalModules = computed(() => {
    return activeModules.value.filter(module => 
      OPTIONAL_MODULES.includes(module.type)
    ).sort((a, b) => a.order - b.order)
  })

  // 获取布局数据
  const fetchLayout = async () => {
    try {
      loading.value = true
      const response = await user.getProfileLayout()

      if (response.data?.code === 200) {
        // 转换布局对象为数组格式
        activeModules.value = convertLayoutToArray(response.data.data.layout)
      }
    } catch (error) {
      console.error('获取布局失败:', error)
      showToast(error.message || '获取布局失败', 'error')
    } finally {
      loading.value = false
    }
  }

  // 获取可用模块
  const fetchAvailableModules = async () => {
    try {
      loading.value = true
      const response = await user.getAvailableModules()

      if (response.data?.code === 200) {
        availableModules.value = response.data.data.modules || []
      }
    } catch (error) {
      console.error('获取可用模块失败:', error)
      showToast(error.message || '获取可用模块失败', 'error')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleId) => {
    try {
      loading.value = true
      console.log('开始移除模块:', moduleId)

      // 找到要移除的模块
      const moduleToRemove = activeModules.value.find(m => m.type === moduleId)
      if (!moduleToRemove) {
        throw new Error('模块不存在')
      }

      // 构建新的布局对象
      const newLayout = {}
      activeModules.value.forEach(module => {
        newLayout[module.type] = {
          order: module.order,
          visible: module.type === moduleId ? false : true
        }
      })

      console.log('新布局:', newLayout)

      // 调用接口更新布局
      const response = await user.updateProfileLayout({ layout: newLayout })
      console.log('更新布局响应:', response)

      if (response.data?.code === 200) {
        // 更新本地状态
        activeModules.value = activeModules.value.filter(m => m.type !== moduleId)
        showToast('模块移除成功', 'success')
      } else {
        throw new Error(response.data?.message || '移除模块失败')
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
      throw error
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      loading.value = true

      // 构建新的布局对象
      const newLayout = { ...activeModules.value.reduce((acc, module) => {
        acc[module.type] = {
          order: module.order,
          visible: true
        }
        return acc
      }, {}) }

      // 添加新模块
      newLayout[moduleType] = {
        order: Object.keys(newLayout).length + 1,
        visible: true
      }

      const response = await user.updateProfileLayout({ layout: newLayout })

      if (response.data?.code === 200) {
        await fetchLayout()  // 重新获取布局
        showToast('模块添加成功', 'success')
      } else {
        throw new Error(response.data?.message || '添加模块失败')
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 更新模块顺序
  const updateOrder = async (newOrder) => {
    try {
      loading.value = true

      // 构建新的布局对象
      const newLayout = newOrder.reduce((acc, module, index) => {
        acc[module.type] = {
          order: index + 1,
          visible: true
        }
        return acc
      }, {})

      const response = await user.updateProfileLayout({ layout: newLayout })

      if (response.data?.code === 200) {
        activeModules.value = newOrder
        showToast('布局更新成功', 'success')
      } else {
        throw new Error(response.data?.message || '更新布局失败')
      }
    } catch (error) {
      console.error('更新布局失败:', error)
      showToast(error.message || '更新布局失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    availableModules,
    coreModules,
    optionalModules,
    fetchLayout,
    fetchAvailableModules,
    removeModule,
    addModule,
    updateOrder
  }
}
